void test_CB_D6_0000()
{
    if (skip_test_CB_D6_0000)
    {
        TEST_SKIP("Skipping");
        return;
    }
    mmap.Reset();
    auto mmapResult = mmap.Initialize(MinRomBankCount, MinVramBankCount, 1, MinWramBankCount);
    TEST_ASSERT_(mmapResult.IsSuccess(), "%s", mmapResult.GetStatusDescription());

    // Initial state

    WriteRegisterWord(RegisterType::PC, 0xF03D);
    WriteRegisterWord(RegisterType::SP, 0xA28F);
    WriteRegisterByte(RegisterType::A, 0xC1);
    WriteRegisterByte(RegisterType::B, 0x7D);
    WriteRegisterByte(RegisterType::C, 0xAC);
    WriteRegisterByte(RegisterType::D, 0x7A);
    WriteRegisterByte(RegisterType::E, 0xD0);
    WriteRegisterFlag(0x20);
    WriteRegisterByte(RegisterType::H, 0xF0);
    WriteRegisterByte(RegisterType::L, 0xA7);
    mmap.EnableIME();
    WriteRegisterByte(RegisterType::IE, 0x01);
    WriteMemory(0xF0A7, 0x98);
    WriteMemory(0xF03E, 0xD6);
    WriteMemory(0xF03D, 0xCB);

    // Execute step
    {
        auto resultByte = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte.IsSuccess(), "%s", resultByte.GetStatusDescription());
        auto ticks = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte), mmap);
        TEST_ASSERT(ticks == GetInstructionTicks(static_cast<const Byte&>(resultByte), 0x00));

        // Execute additional step for prefix
        auto resultByte2 = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte2.IsSuccess(), "%s", resultByte2.GetStatusDescription());
        auto ticks2 = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte2), mmap);
        TEST_ASSERT(ticks2 == GetInstructionTicks(static_cast<const Byte&>(resultByte2), 0xCB));
        TEST_ASSERT(ticks + ticks2 == 16);
    }

    // Final state
            
    CheckRegisterByte(RegisterType::A, 0xC1);
    CheckRegisterByte(RegisterType::B, 0x7D);
    CheckRegisterByte(RegisterType::C, 0xAC);
    CheckRegisterByte(RegisterType::D, 0x7A);
    CheckRegisterByte(RegisterType::E, 0xD0);
    CheckRegisterFlag(0x20);
    CheckRegisterByte(RegisterType::H, 0xF0);
    CheckRegisterByte(RegisterType::L, 0xA7);
    CheckRegisterWord(RegisterType::PC, 0xF03F);
    CheckRegisterWord(RegisterType::SP, 0xA28F);
    TEST_ASSERT(mmap.IMEEnabled());
    CheckMemory(0xF03D, 0xCB);
    CheckMemory(0xF03E, 0xD6);
    CheckMemory(0xF0A7, 0x9C);
}

